const input = $input.first().json ?? {};
const envelope = input.body && typeof input.body === 'object' && !Array.isArray(input.body) ? input.body : input;
const payload = envelope.payload && typeof envelope.payload === 'object' && !Array.isArray(envelope.payload) ? envelope.payload : {};
const toText = (value) => {
  if (value === null || value === undefined) {
    return '';
  }

  return String(value).trim();
};
const toLower = (value) => toText(value).toLowerCase();
const sourceEventType = toText(envelope.eventType);
const eventId = toText(envelope.eventId);
const occurredAtRaw = toText(envelope.occurredAt) || new Date().toISOString();
const occurredAtDate = Number.isNaN(Date.parse(occurredAtRaw)) ? new Date() : new Date(occurredAtRaw);
const ticketId = toText(payload.ticketId) || eventId || 'unknown';
const fullName = toText(payload.fullName) || toText(payload.name) || `${toText(payload.firstName)} ${toText(payload.lastName)}`.trim();
const email = toLower(payload.email);
const preferredChannel = toLower(payload.preferredChannel) || 'email';
const requestedService = toLower(payload.requestedService) || toLower(payload.intent) || toLower(payload.productLine) || sourceEventType;
const urgency = toLower(payload.urgency);
const message = `${toText(payload.message)} ${toText(payload.notes)}`.trim().toLowerCase();
const symptomFlags = Array.isArray(payload.symptomFlags) ? payload.symptomFlags.map((value) => toLower(value)).filter(Boolean) : [];
const referralSource = toText(payload.referralSource) || toText(payload.source) || toText(envelope.source) || 'unknown';
const consentAccepted = Boolean(payload.consentAccepted ?? payload.marketingConsent ?? false);
const riskKeywords = ['urgent', 'pain', 'fall', 'bleeding', 'infection', 'post-op', 'post op', 'respiratory', 'breathing'];
const hasClinicalRisk = symptomFlags.some((value) => riskKeywords.some((keyword) => value.includes(keyword))) || riskKeywords.some((keyword) => message.includes(keyword));
let queueName = 'Website contact follow-up queue';
let operatorOwnerRole = 'contact-desk';
let novuTopicKey = 'operator-intake-general';
if (sourceEventType === 'rental.requested' || requestedService.includes('rental')) {
  queueName = 'Rental request triage queue';
  operatorOwnerRole = 'support-desk';
  novuTopicKey = 'operator-rental-triage';
} else if (sourceEventType === 'order.created' || requestedService.includes('checkout') || requestedService.includes('purchase') || requestedService.includes('order')) {
  queueName = 'Checkout recovery queue';
  operatorOwnerRole = 'ops-queue';
  novuTopicKey = 'operator-checkout-recovery';
}
let triageLevel = 'routine';
if (sourceEventType === 'booking.requested' || requestedService.includes('consult') || requestedService.includes('booking')) {
  triageLevel = 'fast-track';
}
if (urgency === 'high' || urgency === 'urgent' || urgency === 'same-day') {
  triageLevel = 'priority';
}
if (hasClinicalRisk) {
  triageLevel = 'clinical-review';
}
let followUpWindowHours = 24;
if (triageLevel === 'fast-track') {
  followUpWindowHours = 4;
}
if (triageLevel === 'priority') {
  followUpWindowHours = 2;
}
if (triageLevel === 'clinical-review') {
  followUpWindowHours = 1;
}
const followUpDueAt = new Date(occurredAtDate.getTime() + followUpWindowHours * 60 * 60 * 1000).toISOString();
const validationErrors = [];
if (!sourceEventType) {
  validationErrors.push('eventType is required');
}
if (!ticketId || ticketId === 'unknown') {
  validationErrors.push('payload.ticketId or eventId is required');
}
if (!email) {
  validationErrors.push('payload.email is required');
}
const recommendedActions = [
  `Create or upsert the person in Twenty using ${email || 'the submitted email'}`,
  `Route the opportunity into \"${queueName}\"`,
  `Schedule first operator touchpoint by ${followUpDueAt}`,
  `Trigger Novu topic ${novuTopicKey} after CRM sync`
];
if (!consentAccepted) {
  recommendedActions.push('Request explicit consent confirmation before sending benefit-oriented follow-up');
}
if (triageLevel === 'clinical-review') {
  recommendedActions.push('Escalate to a human operator for symptom review before scheduling or selling');
}
const triageId = `triage_${ticketId.replace(/[^a-zA-Z0-9_-]/g, '_')}`;
const responseBody = {
  workflow: 'medtech_intake_triage_router',
  status: validationErrors.length > 0 ? 'invalid' : 'accepted',
  triageId,
  queueName,
  twentyOpportunityName: queueName,
  operatorOwnerRole,
  novuTopicKey,
  triageLevel,
  needsHumanReview: hasClinicalRisk || !consentAccepted,
  followUpDueAt,
  followUpWindowHours,
  escalationLevel: triageLevel === 'clinical-review' ? 'clinical-review' : triageLevel === 'priority' ? 'priority' : 'standard',
  recommendedActions,
  validationErrors,
  normalizedPayload: {
    eventId: eventId || null,
    eventType: sourceEventType,
    occurredAt: occurredAtDate.toISOString(),
    ticketId,
    email,
    fullName: fullName || null,
    phone: toText(payload.phone) || null,
    city: toText(payload.city) || null,
    companyName: toText(payload.companyName) || null,
    requestedService: requestedService || null,
    preferredChannel,
    referralSource,
    urgency: urgency || 'standard',
    consentAccepted,
    symptomFlags,
    bookingWindow: toText(payload.requestedWindow) || null,
    notes: toText(payload.message) || toText(payload.notes) || null
  }
};
return [
  {
    json: {
      responseCode: validationErrors.length > 0 ? 422 : 202,
      responseBody
    }
  }
];
